WHERE rt.is_active = 1
AND rt.hospital_id = #{hospitalId}
AND rt.modality_id = #{modalityId}
AND ( rt.template_name ILIKE '%' || #{searchText} || '%' OR rt.template_content ILIKE '%' || #{searchText} || '%' OR h.name ILIKE '%' || #{searchText} || '%' OR COALESCE(h.abbr, '') ILIKE '%' || #{searchText} || '%' OR m.name ILIKE '%' || #{searchText} || '%' OR COALESCE(m.abbr, '') ILIKE '%' || #{searchText} || '%' )

mapper.select:
SELECT

FROM pacs_result_templates rt


ORDER BY rt.modified_at DESC NULLS LAST, rt.id DESC

    LIMIT #{rowsPerPage}
    OFFSET #{page}

SELECT COUNT(1)
FROM pacs_result_templates
WHERE hospital_id = #{hospitalId}
  AND modality_id = #{modalityId}
  AND is_active = 1
  AND LOWER(TRIM(template_name)) = LOWER(TRIM(#{templateName}))

    AND id != #{excludeId}
